mapper.select:
SELECT * FROM budget_allocations
WHERE fiscal_year = #{fiscalYear} AND budget_type_id = #{budgetTypeId} AND target_category = #{targetCategory}
LIMIT 1

mapper.insert:
INSERT INTO budget_allocations (fiscal_year, budget_type_id, target_category, allocated_amount)
VALUES (#{fiscalYear}, #{budgetTypeId}, #{targetCategory}, #{allocatedAmount})
ON DUPLICATE KEY UPDATE allocated_amount = #{allocatedAmount}
